import { callMcpSkill, callMcpSkillsParallel } from "@/lib/ai/skills/mcp";
import { pickTopSemanticCandidates } from "@/lib/ai/skills/semantic-targeting";

export async function main() {
  const toolId = "5cc326fb-500d-4c17-bc5f-ade143210636";

  const readBatch = await callMcpSkillsParallel({
    label: "fed-fomc-discovery-probe",
    calls: [
      {
        key: "search_markets",
        toolId,
        toolName: "search_markets",
        args: {
          query: "Fed will cut rates at the next FOMC meeting",
          status: "open",
          limit: 20,
          maxSeriesScan: 600
        }
      },
      {
        key: "get_all_categories",
        toolId,
        toolName: "get_all_categories",
        args: {}
      }
    ]
  });

  const searchResult =
    readBatch.results.find((entry) => entry.key === "search_markets")?.status === "fulfilled"
      ? readBatch.results.find((entry) => entry.key === "search_markets")?.value
      : null;

  const searchCandidates = Array.isArray(searchResult?.results) ? searchResult.results : [];

  const ranked = pickTopSemanticCandidates({
    target: "the exact Kalshi binary market for whether the Fed will cut rates at the next FOMC meeting",
    candidates: searchCandidates,
    requiredTerms: ["Fed", "FOMC", "cut", "rates"],
    avoidTerms: ["hold", "pause", "hike", "inflation", "CPI"],
    limit: 3
  });

  const shortlist = Array.isArray(ranked) && ranked.length > 0 ? ranked : searchCandidates.slice(0, 3);

  if (shortlist.length === 0) {
    return {
      found: false,
      missingData: ["No usable candidates returned by search_markets."],
      attemptedBranches: [
        "parallel probe: search_markets(query: Fed will cut rates at the next FOMC meeting, status: open)",
        "parallel probe: get_all_categories()"
      ],
      parallelTelemetry: readBatch.summary
    };
  }

  const selected = shortlist[0];
  const resolvedEventTicker = selected?.eventTicker || null;
  const resolvedTicker = selected?.ticker || null;

  const eventDetails = resolvedEventTicker
    ? await callMcpSkill({
        toolId,
        toolName: "get_event",
        args: {
          eventTicker: resolvedEventTicker,
          withNestedMarkets: true
        }
      })
    : null;

  const eventMarkets = Array.isArray(eventDetails?.markets) ? eventDetails.markets : [];
  const marketFromEvent =
    resolvedTicker
      ? eventMarkets.find((m) => m && m.ticker === resolvedTicker) || null
      : null;

  const marketDetails = resolvedTicker
    ? await callMcpSkill({
        toolId,
        toolName: "get_market",
        args: { ticker: resolvedTicker }
      })
    : null;

  const market = marketDetails?.market || marketFromEvent || null;
  const event = eventDetails?.event || null;

  return {
    found: Boolean(event && market),
    selectedCandidate: selected
      ? {
          title: selected.title || null,
          ticker: selected.ticker || null,
          eventTicker: selected.eventTicker || null,
          yesPrice: selected.yesPrice ?? null,
          closeTime: selected.closeTime || null
        }
      : null,
    event: event
      ? {
          title: event.title,
          status: event.status,
          category: event.category,
          eventTicker: event.eventTicker
        }
      : null,
    market: market
      ? {
          title: market.title,
          ticker: market.ticker,
          status: market.status,
          yesPrice: market.yesPrice,
          noPrice: market.noPrice,
          closeTime: market.closeTime,
          rules: market.rules,
          rulesDetailed: market.rulesDetailed,
          earlyCloseCondition: market.earlyCloseCondition,
          canCloseEarly: market.canCloseEarly,
          url: market.url
        }
      : null,
    missingData: !event || !market ? ["Could not fully confirm event and market after bounded validation."] : [],
    attemptedBranches: [
      "parallel probe: search_markets(query: Fed will cut rates at the next FOMC meeting, status: open)",
      "parallel probe: get_all_categories()",
      "semantic ranking: pickTopSemanticCandidates(target: exact Fed/FOMC rate-cut market)",
      "detail fetch: get_event(eventTicker from shortlist)",
      "detail fetch: get_market(ticker from shortlist)"
    ],
    parallelTelemetry: readBatch.summary,
    fetchedAt: {
      search: searchResult?.fetchedAt || null,
      event: eventDetails?.fetchedAt || null,
      market: marketDetails?.fetchedAt || null
    }
  };
}

