import { callMcpSkill, callMcpSkillsParallel } from "@/lib/ai/skills/mcp";

function getFirstFulfilledValue(batch, key) {
  const entry = batch.results.find((r) => r.key === key);
  return entry && entry.status === "fulfilled" ? entry.value : null;
}

function normalizeTickerFromResult(result) {
  if (!result || !Array.isArray(result.results)) return null;
  const candidates = result.results.filter((m) => m && typeof m.ticker === "string");
  if (candidates.length === 0) return null;
  return candidates[0].ticker;
}

function pickBestNycCandidate(results) {
  const markets = Array.isArray(results) ? results : [];
  if (markets.length === 0) return null;

  const scoreMarket = (m) => {
    const title = `${m.title || ""} ${m.ticker || ""}`.toLowerCase();
    let score = 0;

    if (title.includes("new york") || title.includes("nyc") || title.includes("ny")) score += 5;
    if (title.includes("100")) score += 5;
    if (title.includes("summer")) score += 2;
    if (title.includes("maximum temperature") || title.includes("high temperature")) score += 2;
    if (m.status === "active" || m.status === "open") score += 1;

    return score;
  };

  return markets
    .slice()
    .sort((a, b) => {
      const diff = scoreMarket(b) - scoreMarket(a);
      if (diff !== 0) return diff;
      return (b.volume24h || 0) - (a.volume24h || 0);
    })[0];
}

