import { callMcpSkill, callMcpSkillsParallel } from "@/lib/ai/skills/mcp";

export async function main() {
  const serverId = "5cc326fb-500d-4c17-bc5f-ade143210636";

  const firstBatch = await callMcpSkillsParallel({
    label: "climate-weather-discovery",
    calls: [
      {
        key: "categories",
        toolId: serverId,
        toolName: "get_all_categories",
        args: {}
      },
      {
        key: "seriesClimate",
        toolId: serverId,
        toolName: "get_all_series",
        args: { category: "Climate", limit: 200 }
      },
      {
        key: "trendingClimate",
        toolId: serverId,
        toolName: "discover_trending_markets",
        args: { category: "Climate", limit: 25, sortBy: "volume_24h" }
      }
    ]
  });

  const categories = firstBatch.results.find((r) => r.key === "categories")?.status === "fulfilled"
    ? firstBatch.results.find((r) => r.key === "categories")?.value
    : null;
  const climateSeries = firstBatch.results.find((r) => r.key === "seriesClimate")?.status === "fulfilled"
    ? firstBatch.results.find((r) => r.key === "seriesClimate")?.value
    : null;
  const trendingClimate = firstBatch.results.find((r) => r.key === "trendingClimate")?.status === "fulfilled"
    ? firstBatch.results.find((r) => r.key === "trendingClimate")?.value
    : null;

  const series = Array.isArray(climateSeries?.series) ? climateSeries.series : [];
  const relevantSeries = series.filter((s) => {
    const title = String(s?.title || "").toLowerCase();
    const tags = Array.isArray(s?.tags) ? s.tags.map((t) => String(t).toLowerCase()) : [];
    const blob = `${title} ${tags.join(" ")}`;
    return (
      blob.includes("temp") ||
      blob.includes("temperature") ||
      blob.includes("hurricane") ||
      blob.includes("storm") ||
      blob.includes("weather") ||
      blob.includes("rain") ||
      blob.includes("heat") ||
      blob.includes("wind")
    );
  }).slice(0, 6);

  const seriesTickers = relevantSeries.map((s) => s.ticker).filter(Boolean);

  const browseCalls = seriesTickers.map((seriesTicker) => ({
    key: seriesTicker,
    toolId: serverId,
    toolName: "browse_series",
    args: { seriesTicker, status: "open", limit: 50 }
  }));

  const browsed = browseCalls.length
    ? await callMcpSkillsParallel({
        label: "browse-weather-series",
        calls: browseCalls
      })
    : { results: [], summary: {} };

  const allMarkets = [];
  for (const entry of browsed.results || []) {
    if (entry.status === "fulfilled" && entry.value && Array.isArray(entry.value.markets)) {
      for (const m of entry.value.markets) {
        allMarkets.push({
          ...m,
          seriesTicker: entry.key
        });
      }
    }
  }

  const ranked = allMarkets
    .filter((m) => String(m?.status || "").toLowerCase() === "open")
    .map((m) => {
      const liquidity = Number(m?.liquidity ?? 0);
      const volume24h = Number(m?.volume24h ?? 0);
      const yesPrice = Number(m?.yesPrice ?? NaN);
      const noPrice = Number(m?.noPrice ?? NaN);
      const spread = Number.isFinite(yesPrice) && Number.isFinite(noPrice) ? Math.abs(yesPrice + noPrice - 100) : null;
      const crowdPenalty = (volume24h / 10000) + (liquidity / 25000) + (spread !== null ? Math.max(0, 10 - spread) : 0);
      const opportunityScore = (liquidity / 1000) + (volume24h / 1000) - crowdPenalty;
      return {
        url: m.url,
        title: m.title,
        ticker: m.ticker,
        eventTicker: m.eventTicker,
        seriesTicker: m.seriesTicker,
        yesPrice: m.yesPrice,
        noPrice: m.noPrice,
        liquidity,
        volume24h,
        closeTime: m.closeTime,
        status: m.status,
        crowdProxy: {
          spreadToParity: spread,
          note:
            spread !== null && spread > 4
              ? "less_crowded_proxy"
              : "more_competitive_proxy"
        },
        opportunityScore
      };
    })
    .filter((m) => m.liquidity >= 1000 || m.volume24h >= 500)
    .sort((a, b) => b.opportunityScore - a.opportunityScore)
    .slice(0, 12);

  return {
    fetchedFrom: {
      categories: categories?.fetchedAt || null,
      seriesClimate: climateSeries?.fetchedAt || null,
      trendingClimate: trendingClimate?.fetchedAt || null
    },
    categoryList: Array.isArray(categories?.categoryList) ? categories.categoryList : [],
    climateSeriesMatched: relevantSeries.map((s) => ({
      ticker: s.ticker,
      title: s.title,
      frequency: s.frequency,
      tags: s.tags,
      category: s.category
    })),
    trendingClimateMarkets: Array.isArray(trendingClimate?.trendingMarkets)
      ? trendingClimate.trendingMarkets.slice(0, 10)
      : [],
    shortlistedContracts: ranked,
    notes: {
      definition: "Open, liquid, close-soon contracts with a lighter crowding proxy using volume, liquidity, and price-parity distance.",
      caveat: "This is based on a past query in this chat, not real-time guaranteed current data."
    }
  };
}

