    label: "kalshi-tariff-fed-discovery",
    calls: [
      {
        key: "search",
        toolId: KALSHI_ID,
        toolName: "search_markets",
        args: {
          query: "tariff fed federal reserve rate decision interest rate powell",
          status: "open",
          limit: 50,
          maxSeriesScan: 600,
        },
      },
      {
        key: "probability",
        toolId: KALSHI_ID,
        toolName: "get_markets_by_probability",
        args: {
          probability: "coinflip",
          category: "Economics",
          limit: 50,
          minLiquidity: 1000,
        },
      },
    ],
  });

  const searchRes = batch.results.find((r) => r.key === "search");
  const probRes = batch.results.find((r) => r.key === "probability");

  const searchMarkets = searchRes?.status === "fulfilled" ? normalizeMarkets(searchRes.value?.results, "search_markets") : [];
  const probMarkets = probRes?.status === "fulfilled" ? normalizeMarkets(probRes.value?.markets, "get_markets_by_probability") : [];

  const combined = [...searchMarkets, ...probMarkets];
  const dedup = [];
  const seen = new Set();

  for (const m of combined) {
    if (!m.ticker || seen.has(m.ticker)) continue;
    seen.add(m.ticker);
    if (isRelevant(m) && nearFifty(m)) dedup.push(m);
  }

  const ranked = dedup
    .sort((a, b) => {
      const la = liquidityScore(a);
      const lb = liquidityScore(b);
      if (lb !== la) return lb - la;
      const da = typeof a.yesPrice === "number" ? Math.abs(a.yesPrice - 50) : 999;
      const db = typeof b.yesPrice === "number" ? Math.abs(b.yesPrice - 50) : 999;
      return da - db;
    })
    .slice(0, 5);

  const details = [];
  for (const m of ranked.slice(0, 3)) {
    const market = await callMcpSkill({
      toolId: KALSHI_ID,
      toolName: "get_market",
      args: { ticker: m.ticker },
    });

    details.push({
      title: market?.market?.title ?? m.title,
      ticker: market?.market?.ticker ?? m.ticker,
      yesPrice: market?.market?.yesPrice ?? m.yesPrice,
      liquidity: market?.market?.liquidity ?? m.liquidity,
      volume24h: market?.market?.volume24h ?? m.volume24h,
      closeTime: market?.market?.closeTime ?? m.closeTime,
      url: market?.market?.url ?? m.url,
      rules: market?.market?.rules ?? "",
      canCloseEarly: market?.market?.canCloseEarly ?? null,
      earlyCloseCondition: market?.market?.earlyCloseCondition ?? "",
      eventTicker: market?.market?.eventTicker ?? m.eventTicker,
      score: liquidityScore({
        ...m,
        liquidity: market?.market?.liquidity ?? m.liquidity,
        volume24h: market?.market?.volume24h ?? m.volume24h,
      }),
    });
  }

  const bestSuited = [...details].sort((a, b) => b.score - a.score).slice(0, 3);

  return {
    fetchedAt: new Date().toISOString(),
    counts: {
      searchMarkets: searchMarkets.length,
      probabilityMarkets: probMarkets.length,
      relevantNearFifty: dedup.length,
      analyzed: details.length,
    },
    bestSuited,
    candidates: details,
    partialFailures: batch.results
      .filter((r) => r.status === "rejected")
      .map((r) => ({ key: r.key, error: String(r.error) })),
    note:
      "These results come from a past query in this chat and should be treated as a snapshot, not live real-time data. I ranked for near-50% pricing, liquidity, and tradeability; rules/close times were verified on the top shortlist.",
  };
}

