import { pickTopSemanticCandidates } from "@/lib/ai/skills/semantic-targeting";

export async function main() {
  const toolId = "5cc326fb-500d-4c17-bc5f-ade143210636";
  const ticker = "KXMVECROSSCATEGORY-S2026024255C44DA-14312DBC41F";

  // Probe: fetch the direct instrument and liquidity diagnostics in parallel
  // (different endpoints only; no same-endpoint batching).
  const readBatch = await callMcpSkillsParallel({
    label: "kalshi-direct-contract-probe",
    calls: [
      {
        key: "market",
        toolId,
        toolName: "get_market",
        args: { ticker }
      },
      {
        key: "liquidity",
        toolId,
        toolName: "analyze_market_liquidity",
        args: { ticker }
      }
    ]
  });

  const marketEntry = readBatch.results.find((r) => r.key === "market");
  const liquidityEntry = readBatch.results.find((r) => r.key === "liquidity");

  const market = marketEntry && marketEntry.status === "fulfilled" ? marketEntry.value?.market : null;
  const liquidity = liquidityEntry && liquidityEntry.status === "fulfilled" ? liquidityEntry.value : null;

  // Decide: if the direct market lookup is weak or missing, do a bounded fallback search.
  // Use deterministic semantic targeting before selecting any fallback candidate.
  let fallbackCandidate = null;
  let fallbackSearch = null;

  if (!market || !market.ticker) {
    fallbackSearch = await callMcpSkill({
      toolId,
      toolName: "search_markets",
      args: {
        query: ticker,
        status: "open",
        limit: 10,
        maxSeriesScan: 200
      }
    });

    const candidates = Array.isArray(fallbackSearch?.results) ? fallbackSearch.results : [];
    const ranked = pickTopSemanticCandidates({
      target: "exact direct Kalshi contract matching the provided ticker and title",
      candidates,
      requiredTerms: ["Chicago", "Houston", "Over"],
      avoidTerms: ["primary", "district", "local"],
      limit: 1
    });

    fallbackCandidate = Array.isArray(ranked) && ranked.length > 0 ? ranked[0] : null;
  }

  // Execute: keep local filtering, ranking, and packaging serial after the read batch.
  const resolvedMarket = market || fallbackCandidate || null;
  const title = resolvedMarket?.title || "yes Chicago,yes Houston,yes Over 261.5 points scored,yes Over 213.5 points scored";
  const components = String(title)
    .split(",")
    .map((s) => s.trim())
    .filter(Boolean);

  const contractSummary = {
    intent: "Direct multi-leg Kalshi contract",
    description:
      "A four-part outcome contract tied to both cities being selected/affirmed and two scoring thresholds being met: Chicago, Houston, Over 261.5 points scored, and Over 213.5 points scored.",
    components
  };

  const tradingSignals = {
    openInterest: resolvedMarket?.openInterest ?? null,
    liquidity: resolvedMarket?.liquidity ?? null,
    volume: resolvedMarket?.volume ?? null,
    yesPrice: resolvedMarket?.yesPrice ?? null,
    noPrice: resolvedMarket?.noPrice ?? null,
    closeTime: resolvedMarket?.closeTime ?? null,
    url: resolvedMarket?.url ?? null,
    liquidityScore: liquidity?.liquidityScore ?? null,
    spread: liquidity?.spread ?? null,
    depth: liquidity?.depth ?? null,
    recommendation: liquidity?.recommendation ?? null,
    slippageSimulation: liquidity?.slippageSimulation ?? null
  };

  const hasTradeSignal =
    (typeof resolvedMarket?.openInterest === "number" && resolvedMarket.openInterest > 0) ||
    (typeof resolvedMarket?.liquidity === "number" && resolvedMarket.liquidity > 0) ||
    (typeof liquidity?.depth?.totalDepthUsd === "number" && liquidity.depth.totalDepthUsd > 0);

  return {
    plan: [
      "Probe the direct market with get_market and liquidity with analyze_market_liquidity in parallel.",
      "If the direct ticker is not resolved cleanly, do one bounded search fallback with search_markets.",
      "Rank any noisy fallback candidates with pickTopSemanticCandidates before selecting a final contract.",
      "Package the final summary serially after reads complete."
    ],
    directInstrumentIntent: true,
    contractSummary,
    tradingSignals,
    hasOpenInterestOrLiquiditySignal: hasTradeSignal,
    readBatchTelemetry: readBatch.summary,
    partialFailures: readBatch.results
      .filter((r) => r.status === "rejected")
      .map((r) => ({ key: r.key, error: r.error })),
    fallbackUsed: Boolean(fallbackCandidate),
    fallbackSearch: fallbackSearch
      ? {
          count: fallbackSearch.count ?? null,
          topCandidateTicker: fallbackCandidate?.ticker ?? null
        }
      : null
  };
}

